import React, { useEffect, useState } from "react";
import api from "../api";

export default function Dashboard({ username, onLogout }) {
  const [transactions, setTransactions] = useState([]);
  const [loans, setLoans] = useState([]);
  const [loanForm, setLoanForm] = useState({
    principal: "",
    interestRate: "",
    tenureMonths: "",
  });
  const [info, setInfo] = useState("");

  useEffect(() => {
    loadData();
    
  }, [username]);

  const loadData = async () => {
    try {
      const t = await api.get("/customer/transactions", {
        params: { username },
      });
      setTransactions(t.data);
      const l = await api.get("/customer/loans", { params: { username } });
      setLoans(l.data);
    } catch {
      setInfo("Error loading data. Please ensure backend is running.");
    }
  };

  const requestChequeBook = async () => {
    try {
      const res = await api.post("/customer/checkbook", null, {
        params: { username },
      });
      setInfo(res.data);
    } catch {
      setInfo("Error requesting cheque book");
    }
  };

  const applyLoan = async (e) => {
    e.preventDefault();
    try {
      const payload = {
        principal: parseFloat(loanForm.principal),
        interestRate: parseFloat(loanForm.interestRate),
        tenureMonths: parseInt(loanForm.tenureMonths, 10),
      };
      const res = await api.post("/customer/loan", payload, {
        params: { username },
      });
      setInfo(`Loan applied. Status: ${res.data.status}`);
      loadData();
    } catch {
      setInfo("Error applying for loan");
    }
  };

  const handleLoanChange = (e) => {
    setLoanForm({ ...loanForm, [e.target.name]: e.target.value });
  };

  return (
    <div className="dashboard">
      <header className="top-bar">
        <div>
          <h1>Secure Bank</h1>
          <p className="subtitle">Welcome, {username}</p>
        </div>
        <button onClick={onLogout}>Logout</button>
      </header>

      <div className="grid-2">
        <section className="panel">
          <h2>Recent Transactions</h2>
          <table>
            <thead>
              <tr>
                <th>Time</th>
                <th>Type</th>
                <th>Amount</th>
                <th>Description</th>
              </tr>
            </thead>
            <tbody>
              {transactions.map((t) => (
                <tr key={t.id}>
                  <td>{t.timestamp}</td>
                  <td>{t.type}</td>
                  <td>{t.amount}</td>
                  <td>{t.description}</td>
                </tr>
              ))}
              {transactions.length === 0 && (
                <tr>
                  <td colSpan="4" style={{ textAlign: "center" }}>
                    No transactions yet.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </section>

        <section className="panel">
          <h2>Chequebook</h2>
          <p>Request a new chequebook for your primary account.</p>
          <button onClick={requestChequeBook}>Request Chequebook</button>

          <h2 style={{ marginTop: "24px" }}>Apply for Loan</h2>
          <form onSubmit={applyLoan} className="loan-form">
            <input
              name="principal"
              placeholder="Principal (₹)"
              onChange={handleLoanChange}
              required
            />
            <input
              name="interestRate"
              placeholder="Interest Rate (%)"
              onChange={handleLoanChange}
              required
            />
            <input
              name="tenureMonths"
              placeholder="Tenure (months)"
              onChange={handleLoanChange}
              required
            />
            <button type="submit">Apply</button>
          </form>

          <h3>Your Loans / EMI Status</h3>
          <ul className="loans-list">
            {loans.map((l) => (
              <li key={l.id}>
                ₹{l.principal} • {l.status}
              </li>
            ))}
            {loans.length === 0 && <li>No loans yet.</li>}
          </ul>
        </section>
      </div>

      {info && <p className="info">{info}</p>}
    </div>
  );
}
